/**
 * Unit tests for domain-resolver
 *
 * TDD PHASE 1: Write failing tests BEFORE implementation
 * Tests domain-sources.json loading and transformation to domainLookup format
 */

import { loadDomainLookup } from '../../src/config/domain-resolver';

describe('domain-resolver', () => {
  describe('loadDomainLookup', () => {
    it('should load and transform domain-sources.json into domainLookup format', () => {
      const lookup = loadDomainLookup();

      // Should have category keys from domain-sources.json
      expect(lookup).toHaveProperty('financial');
      expect(lookup).toHaveProperty('newsletter');
      expect(lookup).toHaveProperty('logistics');
      expect(lookup).toHaveProperty('household');

      // Should NOT have metadata key (non-category data)
      expect(lookup).not.toHaveProperty('metadata');
    });

    it('should group domains by confidence level for financial category', () => {
      const lookup = loadDomainLookup();

      expect(lookup.financial).toHaveProperty('highConfidence');
      expect(lookup.financial).toHaveProperty('mediumConfidence');
      expect(lookup.financial).toHaveProperty('lowConfidence');

      // High confidence domains
      expect(lookup.financial.highConfidence).toContainEqual({
        domain: 'chase.com',
        type: 'bank',
      });
      expect(lookup.financial.highConfidence).toContainEqual({
        domain: 'americanexpress.com',
        type: 'card',
      });

      // Medium confidence domains
      expect(lookup.financial.mediumConfidence).toContainEqual({
        domain: 'paypal.com',
        type: 'payment_processor',
      });
      expect(lookup.financial.mediumConfidence).toContainEqual({
        domain: 'stripe.com',
        type: 'payment_processor',
      });

      // Low confidence domains
      expect(lookup.financial.lowConfidence).toContainEqual({
        domain: 'smarthub.coop',
        type: 'utility',
      });

      // Verify no domains in wrong confidence tier
      expect(lookup.financial.highConfidence).not.toContainEqual({
        domain: 'paypal.com',
        type: 'payment_processor',
      });
    });

    it('should handle domains without type property', () => {
      const lookup = loadDomainLookup();

      // Newsletter domains don't have type in source
      expect(lookup.newsletter.highConfidence).toContainEqual({
        domain: 'medium.com',
      });

      // Should not have undefined type property
      const mediumDomain = lookup.newsletter.highConfidence.find((d) => d.domain === 'medium.com');
      expect(mediumDomain).toBeDefined();
      expect(mediumDomain?.type).toBeUndefined();
    });

    it('should preserve type information when present', () => {
      const lookup = loadDomainLookup();

      const chaseDomain = lookup.financial.highConfidence.find((d) => d.domain === 'chase.com');
      expect(chaseDomain).toBeDefined();
      expect(chaseDomain?.type).toBe('bank');

      const fedexDomain = lookup.logistics.highConfidence.find((d) => d.domain === 'fedex.com');
      expect(fedexDomain).toBeDefined();
      expect(fedexDomain?.type).toBe('carrier');
    });

    it('should handle empty confidence tiers gracefully', () => {
      const lookup = loadDomainLookup();

      // Some categories may not have low confidence domains
      // Verify structure still exists (empty array)
      for (const category of Object.values(lookup)) {
        expect(category).toHaveProperty('highConfidence');
        expect(category).toHaveProperty('mediumConfidence');
        expect(category).toHaveProperty('lowConfidence');
        expect(Array.isArray(category.highConfidence)).toBe(true);
        expect(Array.isArray(category.mediumConfidence)).toBe(true);
        expect(Array.isArray(category.lowConfidence)).toBe(true);
      }
    });

    it('should handle missing domain-sources.json gracefully', () => {
      // This test will verify error handling when file doesn't exist
      // For now, we expect the actual file to exist, but implementation should
      // gracefully handle missing files with empty lookup

      // Mock the config loader to simulate missing file
      // For now, just verify current behavior with existing file
      const lookup = loadDomainLookup();
      expect(lookup).toBeDefined();
      expect(typeof lookup).toBe('object');
    });

    it('should return empty arrays for confidence tiers with no domains', () => {
      const lookup = loadDomainLookup();

      // Newsletter likely has no low confidence domains
      if (lookup.newsletter) {
        expect(Array.isArray(lookup.newsletter.lowConfidence)).toBe(true);
        // May be empty, but should be an array
        expect(lookup.newsletter.lowConfidence.length).toBeGreaterThanOrEqual(0);
      }
    });

    it('should have correct structure matching HardAssertionStageConfig', () => {
      const lookup = loadDomainLookup();

      // Type structure should match:
      // Record<string, {
      //   highConfidence: Array<{ domain: string; type?: string }>;
      //   mediumConfidence: Array<{ domain: string; type?: string }>;
      //   lowConfidence: Array<{ domain: string; type?: string }>;
      // }>

      for (const categoryLookup of Object.values(lookup)) {
        // Verify each category has the three arrays
        expect(categoryLookup).toHaveProperty('highConfidence');
        expect(categoryLookup).toHaveProperty('mediumConfidence');
        expect(categoryLookup).toHaveProperty('lowConfidence');

        // Verify each array contains objects with domain property
        for (const confidenceTier of [
          categoryLookup.highConfidence,
          categoryLookup.mediumConfidence,
          categoryLookup.lowConfidence,
        ]) {
          for (const entry of confidenceTier) {
            expect(entry).toHaveProperty('domain');
            expect(typeof entry.domain).toBe('string');
            // Type is optional
            if ('type' in entry) {
              expect(typeof entry.type).toBe('string');
            }
          }
        }
      }
    });

    it('should not duplicate domains across confidence tiers', () => {
      const lookup = loadDomainLookup();

      for (const [categoryName, categoryLookup] of Object.entries(lookup)) {
        const allDomains = new Set<string>();
        const duplicates = new Set<string>();

        for (const tier of [
          categoryLookup.highConfidence,
          categoryLookup.mediumConfidence,
          categoryLookup.lowConfidence,
        ]) {
          for (const entry of tier) {
            if (allDomains.has(entry.domain)) {
              duplicates.add(entry.domain);
            }
            allDomains.add(entry.domain);
          }
        }

        expect(duplicates.size).toBe(0);
        if (duplicates.size > 0) {
          // Helpful error message if there are duplicates
          console.error(`Category ${categoryName} has duplicate domains: ${Array.from(duplicates).join(', ')}`);
        }
      }
    });

    it('should handle malformed domain-sources.json gracefully', () => {
      // This test documents expected behavior when domain-sources.json is malformed
      // Implementation should:
      // 1. Log a warning
      // 2. Return empty lookup object {}
      // 3. Not throw an error (graceful degradation)

      // For now, verify normal operation
      const lookup = loadDomainLookup();
      expect(lookup).toBeDefined();
    });
  });
});

