   463→      topLevelCategories: this.config.processingConfig.topLevelCategories,
   464→      settings: this.config.processingConfig.settings.ruleScoring,
   465→      tuningParameters: {
   466→        // Map config values (KHigh, KMedium, KLow) to internal names (K_high, K_medium, K_low)
   467→        // These represent tier weights in the rule scoring algorithm
   468→        K_high: tuningParams?.KHigh ?? 1,
   469→        K_medium: tuningParams?.KMedium ?? 0.7,
   470→        K_low: tuningParams?.KLow ?? 0.3,
   471→        // M_medium and M_low are multipliers for medium/low confidence rules
   472→        // Default to values that allow graceful degradation
   473→        M_medium: tuningParams?.KMedium ?? 0.7,
   474→        M_low: tuningParams?.KLow ?? 0.3,
   475→        // TAIL_DAMPEN and TAIL_RATIO_CAP control score aggregation behavior
