   581→        minSecondaryConfidence: this.config.processingConfig.multiLabelPolicy.minConfidenceForAdditional,
   582→        allowedCombinations: [],
   583→      },
   584→    };
   585→  }
   586→
   587→  /**
   588→   * Extract configuration for action determination stage
   589→   */
   590→  private getActionDeterminationConfig(): ActionDeterminationConfig {
   591→    return {
   592→      archiveThresholds: {
   593→        lowImportance: 0.3,
   594→        mediumImportance: 0.5,
   595→        highImportance: 0.7,
   596→      },
   597→      defaultArchiveThreshold: 'mediumImportance',
   598→      actionSettings: {
   599→        archiveIfBelowThreshold: true,
   600→        markAsReadIfArchived: false,
   601→        applyCustomActions: false,
   602→      },
   603→    };
   604→  }
   605→
   606→  /**
   607→   * Execute classification pipeline on single email
   608→   *
   609→   * Uses the StageTask architecture for consistent pipeline execution.
   610→   * This method now delegates to classifyWithStageTask for unified pipeline logic.
   611→   *
   612→   * @param email - Email message to classify
   613→   * @returns Complete classification result with selected labels
   614→   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   615→   */
   616→  async classify(email: EmailMessage): Promise<ClassificationResult> {
   617→    // Delegate to StageTask architecture (no replay, execute all stages)
   618→    return this.classifyWithStageTask(email);
   619→  }
   620→
   621→  /**
   622→   * Process multiple emails sequentially with shared session context
   623→   *
   624→   * Uses the StageTask architecture for consistent pipeline execution.
   625→   * Each email is processed independently using classifyWithStageTask.
   626→   *
   627→   * @param emails - Array of email messages to classify
   628→   * @returns Array of classification results or error results
   629→   */
   630→  async classifyBatch(emails: EmailMessage[]): Promise<Array<ClassificationResult | ClassificationErrorResult>> {
   631→    const results: Array<ClassificationResult | ClassificationErrorResult> = [];
   632→
   633→    // Create batch session for tracking
   634→    const session = createClassificationSession(
   635→      this.config.processingConfig,
   636→      'sequential',
   637→      emails.length,
   638→      this.testMode
   639→    );
   640→
   641→    for (let i = 0; i < emails.length; i++) {
   642→      const email = emails[i];
   643→      const startTime = Date.now();
   644→      try {
   645→        // Use StageTask architecture for consistent pipeline execution
   646→        const result = await this.classifyWithStageTask(email);
   647→
   648→        // Update batch position and session tracking
   649→        result.batchPosition = i;
   650→        result.sessionId = session.id;
   651→        incrementSessionSuccess(session);
   652→
   653→        results.push(result);
   654→      } catch (error) {
   655→        // Continue processing batch on individual email error
   656→        incrementSessionError(session, email.id, 'pipeline', error instanceof Error ? error.message : String(error));
   657→        results.push({
   658→          error: error instanceof Error ? error : new Error(String(error)),
   659→          emailId: email.id,
   660→          processingDurationMs: Date.now() - startTime,
   661→        });
   662→      }
   663→    }
   664→
   665→    // Finalize session after all emails processed
   666→    finalizeClassificationSession(session);
   667→
   668→    return results;
   669→  }
   670→}
